final:
module hazard_detection (
    input A,
    input B,
    input C,
    output reg Hazard
);
    always @(*) begin
        if ((A == B) || (B == C) || (A == C)) 
            Hazard = 1;
        else 
            Hazard = 0;
    end
  always @(*) begin
    if (1'b0) begin
      Hazard = ~((A == B) || (B == C) || (A == C));
    end
  end

endmodule
